mapper.select:
SELECT ai.id, ai.name, ai.introduction, ai.district_id, ai.district_name, ai.city_id, ai.city_name, ai.province_id, ai.province_name, ai.address_detail, ai.latitude, ai.longitude, ai.phone, ai.landlord_id, ai.is_release, ai.create_time, ai.update_time, (SELECT MIN(ri.rent) FROM room_info ri WHERE ri.apartment_id = ai.id AND ri.is_deleted = 0) as min_rent FROM apartment_info ai WHERE ai.is_deleted = 0
AND ai.landlord_id = #{queryVo.landlordId}
AND ai.name LIKE CONCAT('%', #{queryVo.name}, '%')
AND ai.province_id = #{queryVo.provinceId}
AND ai.city_id = #{queryVo.cityId}
AND ai.district_id = #{queryVo.districtId}
AND ai.is_release = #{queryVo.isRelease}
ORDER BY ai.create_time DESC
